class Solution:
    def minimumCost(self, m, n, horizontalCut, verticalCut):
        # Brute force DP for small sizes
        from functools import lru_cache
        # prefix sums for row/col sums
        @lru_cache(maxsize=None)
        def dp(r1, r2, c1, c2):
            if r2 - r1 == 1 and c2 - c1 == 1:
                return 0
            best = float('inf')
            for r in range(r1, r2 - 1):
                cost = horizontalCut[r] + dp(r1, r+1, c1, c2) + dp(r+1, r2, c1, c2)
                best = min(best, cost)
            for c in range(c1, c2 - 1):
                cost = verticalCut[c] + dp(r1, r2, c1, c+1) + dp(r1, r2, c+1, c2)
                best = min(best, cost)
            return best
        return dp(0, m, 0, n)

