var minimumCost = function(m, n, horizontalCut, verticalCut) {
    const hcuts = [...horizontalCut].sort((a, b) => b - a);
    const vcuts = [...verticalCut].sort((a, b) => b - a);
    let hPieces = 1, vPieces = 1;
    let hi = 0, vi = 0, total = 0;
    while (hi < hcuts.length && vi < vcuts.length) {
        if (hcuts[hi] >= vcuts[vi]) {
            total += hcuts[hi] * vPieces;
            hPieces++; hi++;
        } else {
            total += vcuts[vi] * hPieces;
            vPieces++; vi++;
        }
    }
    while (hi < hcuts.length) { total += hcuts[hi] * vPieces; hPieces++; hi++; }
    while (vi < vcuts.length) { total += vcuts[vi] * hPieces; vPieces++; vi++; }
    return total;
};
